class Solution {

    private int m, n;
    private int[] row;
    private int[] col;
    private int count;

    public Solution(int m, int n) {
        this.m = m;
        this.n = n;
        this.row = new int[m];
        this.col = new int[n];
        this.count = m * n;
    }

    public int[] flip() {
        if (count == 0) return null;
        int idx = (int) (Math.random() * count--);
        int i = idx / n;
        int j = idx % n;
        row[i]++;
        col[j]++;
        return new int[] { i, j };
    }

    public void reset() {
        count = m * n;
        Arrays.fill(row, 0);
        Arrays.fill(col, 0);
    }
}
